import os
from pathlib import PurePath, Path
from typing import List

from geosat.tools.urlprotocol.urlprotocol import UrlProtocol


class LocalUrlProtocol(UrlProtocol):
    """Protocol that handles requests to local urls"""

    @staticmethod
    def get_scheme() -> str:
        return ""

    def extract_path(self, url: str) -> PurePath:
        return PurePath(url)

    def integrate_path(self, url: str, path: PurePath) -> str:
        return str(path.__class__(url) / path.name)

    def request(self, url: str) -> List[str]:
        input_path = Path(url)
        if input_path.is_file():
            return [url]
        return [str(path) for path in input_path.rglob("*")]

    def exists(self, url: str) -> bool:
        return Path(url).exists()

    def list(self, url: str) -> list:
        return [str(path) for path in Path(url).glob("*")]

    def pull(self, url: str) -> str:
        if not Path(url).is_file():
            raise FileNotFoundError(url)
        return url

    def push(self, url: str) -> str:
        return url

    def receive(self, url: str, stream):
        with open(url, mode="rb") as file:
            stream.write(file.read())

    def send(self, url: str, stream):
        with open(url, mode="wb") as file:
            file.write(stream.read())

    def delete_cache(self, url: str) -> str:
        return url

    def remove(self, url: str):
        os.remove(url)

    def open(self, path: str, mode: str):
        return open(path, mode)
